={{ (function() {
  var d = $input.first().json;
  if (!d.tenantId) return 'SELECT 1';
  function safe(s) { return String(s || '').replace(/'/g, "''").substring(0, 500); }
  var notes = safe('CallSid:' + (d.callSid||'') + ' Q: ' + (d.speechResult || '').substring(0, 200) + ' - R: ' + (d.aiReply || '').substring(0, 300) + (d.toolUsed ? ' [TOOL:' + d.toolUsed + ']' : ''));
  return "INSERT INTO call_logs (id, tenant_id, call_sid, from_number, to_number, direction, status, duration, notes, created_at, updated_at) "
    + "VALUES (gen_random_uuid(), '" + d.tenantId + "', '" + safe(d.callSid) + "', '" + safe(d.from) + "', '', 'inbound', 'completed', 0, '" + notes + "', NOW(), NOW()) "
    + "ON CONFLICT DO NOTHING";
})() }}

