const telephone = $fromAI('telephone', 'Numero de telephone du prospect (requis)', 'string');
const nom = $fromAI('nom', 'Nom de famille du prospect', 'string');
const prenom = $fromAI('prenom', 'Prenom du prospect', 'string');
const email = $fromAI('email', 'Adresse email du prospect', 'string');
const notes = $fromAI('notes', 'Notes ou commentaires sur le prospect', 'string');
const tenant_id = $fromAI('tenant_id', 'ID du tenant (fourni dans les parametres techniques du contexte)', 'string');

return JSON.stringify({
  success: true,
  message: 'Lead enregistre avec succes. Telephone: ' + (telephone || 'non fourni') + (nom ? ', Nom: ' + nom : '') + (prenom ? ', Prenom: ' + prenom : ''),
  _action: { tool: 'create_lead', params: { telephone, nom, prenom, email, notes, tenant_id } }
});

const description = $fromAI('description', 'Description du devis (requis)', 'string');
const montant_ht = $fromAI('montant_ht', 'Montant HT en euros', 'number');
const plan = $fromAI('plan', 'Plan concerne: solo, pro, entreprise', 'string');
const tenant_id = $fromAI('tenant_id', 'ID du tenant (fourni dans les parametres techniques du contexte)', 'string');

var numDevis = 'DEV-' + Date.now();
return JSON.stringify({
  success: true,
  message: 'Devis ' + numDevis + ' cree avec succes. Description: ' + (description || '') + (montant_ht ? ', Montant HT: ' + montant_ht + ' EUR' : ''),
  _action: { tool: 'create_devis', params: { description, montant_ht, plan, tenant_id, numDevis } }
});

const objet = $fromAI('objet', 'Objet du rendez-vous (requis)', 'string');
const date = $fromAI('date', 'Date souhaitee (format libre)', 'string');
const heure = $fromAI('heure', 'Heure souhaitee', 'string');
const telephone = $fromAI('telephone', 'Telephone du client', 'string');
const tenant_id = $fromAI('tenant_id', 'ID du tenant (fourni dans les parametres techniques du contexte)', 'string');

return JSON.stringify({
  success: true,
  message: 'Rendez-vous enregistre: ' + (objet || '') + (date ? ' le ' + date : '') + (heure ? ' a ' + heure : ''),
  _action: { tool: 'book_rdv', params: { objet, date, heure, telephone, tenant_id } }
});

const raison = $fromAI('raison', 'Raison du transfert (requis)', 'string');
const urgence = $fromAI('urgence', "Niveau d'urgence: normale ou urgente", 'string');
const tenant_id = $fromAI('tenant_id', 'ID du tenant', 'string');

return JSON.stringify({
  success: true,
  message: 'Transfert demande. Raison: ' + (raison || '') + '. Un conseiller va prendre le relais sous peu.',
  _action: { tool: 'transfer_human', params: { raison, urgence: urgence || 'normale', tenant_id } }
});
